def factorial(n):
    if n < 0:
        return "Factorial not defined for negative numbers"
    elif n == 0 or n == 1:
        return 1
    else:
        fact = 1
        for i in range(2, n + 1):
            fact *= i
        return fact

# Example usage
num = 5
print(f"The factorial of {num} is {factorial(num)}")  # Output: The factorial of 5 is 120

def add(x, y):
    return x + y

def subtract(x, y):
    return x - y

def multiply(x, y):
    return x * y

def divide(x, y):
    return x / y

print("Select: 1.Add 2.Subtract 3.Multiply 4.Divide")
